var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"왔는가. 레아 슈나이더.","JPN":"来たか、レア・シュナイダー。","ENG":"You are here, Leah Schneider.","TWN":"你來了，蕾亞·修奈德。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네. 하지만 여자를 혼자 내버려 두고 훌쩍 떠나가 버리다니, 매너가 없네요.","JPN":"はい、それにしても、女性一人を置いてふらっといなくなるなんて失礼ですね。","ENG":"Yes. But how rude of you to leave a lady all alone.","TWN":"對，你竟然丟下女生自己跑掉，很沒風度欸。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너와 사연이 있는 인물이라고 여겨 잠시 자리를 내 주었을 뿐이다.","JPN":"そなたが二人きりで話したい人物だろうと思い、しばらく外していただけだ。","ENG":"I simply provided some privacy because I deemed her story important to you.","TWN":"我知道那個人和你之間發生過很多事，所以才給你們獨處的時間。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이야기는 충분히 나누었나?","JPN":"話はできたか？","ENG":"Have you exchanged words?","TWN":"聊得盡興嗎？"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"덕분에요. 조금은 기운을 차렸다고나 할까요.","JPN":"おかげさまで。少しは元気になったと言いますか。","ENG":"Yes, thanks to you. I'm feeling a bit better.","TWN":"嗯，托你的福，我好像有稍微恢復一些活力。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"이 열차에 모여 있는 것들은…. 모두 네퀴티아가 겪었던 실패의 경험일 거예요.","JPN":"この列車に集められているのは……すべてネキティアが経験してきた失敗の数々なんだと思います。","ENG":"I think... everything in this train is the experience of Nequitia's failure.","TWN":"這列車裡的一切…都是莉奎蒂亞經歷過的失敗。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"몽타뉴도, 결국 그 때 끝장을 내지 못하는 바람에 귀찮게 된 상대였으니까.","JPN":"モンターニュも結局、あの時トドメを刺さなかったせいで面倒なことになった相手ですからね。","ENG":"Montagne, too, was someone who became a problem later on because she couldn't finish her off at first.","TWN":"譬如蒙塔妮，是因為當時一時心軟而留下的遺毒。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하지만 저에게는 그렇지 않아요.","JPN":"でも私にとってはそうじゃありません。","ENG":"But that isn't how I see it.","TWN":"但對我來說並非如此。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"적의 생명을 구해 줬다는 건, 저에게 무른 면이 있다는 상징이나 마찬가지니까요.","JPN":"敵の命を奪わなかったことは、自分に甘い側面があるという証拠のようなものですから。","ENG":"Sparing the life of an enemy means that I have a soft side too.","TWN":"留下敵人的性命，就說明我的內心還保留著柔軟的一面。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"너와 그녀가 다르다고 말하고 싶은 것인가.","JPN":"そなたと彼女は違うと言いたいのか。","ENG":"Do you wish to say that you are different from her?","TWN":"你是想說，你和她不一樣。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"맞아요. 그래서 저도 여기 있는 것 아닐까요?","JPN":"はい。だから私は今ここにいるんじゃないでしょうか？","ENG":"Yes. Maybe that's why I'm in here too.","TWN":"沒錯。所以我才會站在這裡，不是嗎？"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"오히려 의문스러운 건 그쪽이에요. 에클레시아.","JPN":"むしろ怪しいのはそっちです。エクレシア。","ENG":"Rather, you're the one I'm not sure about, Ecclesia.","TWN":"我有疑問的反而是你，艾可露西亞。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그 성전에서 탈출하기 전에 셰나에게 들었거든요. 당신에 대해서.","JPN":"あの聖殿から逃げる前に、シェナから聞いたんです。あなたについて。","ENG":"I heard about you. From Shena, before I escaped the temple.","TWN":"從聖殿逃出來之前，世娜說了有關你的事情。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"꽤나 대접 받던 몸이었던 것 같은데, 어쩌다 이 열차에 갇히게 된 거죠?","JPN":"かなり高い地位にあったようですけど、どうしてこの列車に閉じ込められたんですか？","ENG":"Seems like you were in a pretty good position. How did you end up trapped on this train?","TWN":"你應該曾經是一個蠻有地位的人，為什麼會被困在這台列車裡？"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그 질문에 대한 답은 다음 객차에 있을 터.","JPN":"その質問への答えは次の客車にあるはずだ。","ENG":"The next passenger vehicle should hold the answer to that question.","TWN":"答案就在下一節車廂裡。"},"stage":{"bg":"TRAIL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"말보다는 직접 보여 주는 편이 설명에 용이하겠지.","JPN":"言葉より直接見せた方が説明しやすいだろう。","ENG":"It would be more convenient to show you than to tell you.","TWN":"我說再多都沒用，不如你親自去看看。"},"stage":{"bg":"TRAIL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};